INSERT INTO `chat_history` (`id`, `user_message`, `bot_response`, `created_at`) VALUES
(1, 'Hii', NULL, '2025-10-13 06:51:17'),
(2, '', 'Hello! How can I assist you today?', '2025-10-13 06:51:18'),
(3, 'give me html sample code', NULL, '2025-10-13 06:51:29'),
(4, '', 'Sure, here is a simple HTML code example:\n\n```html\n<!DOCTYPE html>\n<html>\n<head>\n    <title>My First Web Page</title>\n</head>\n<body>\n    <h1>Welcome to My Website</h1>\n    <p>This is a paragraph of text on my web page.</p>\n    <a href=\"https://www.example.com\">Click here to visit Example website</a>\n</body>\n</html>\n```\n\nThis code will display a basic webpage with a heading, a paragraph of text, and a link to an external website.', '2025-10-13 06:51:31'),
(5, 'Hey I\'m Fuu', NULL, '2025-10-13 14:16:43'),
(6, '', 'Nice to meet you Fuu! How can I assist you today?', '2025-10-13 14:16:45'),
(7, 'show me something', NULL, '2025-10-13 14:16:55'),
(8, '', 'I\'m sorry, I am a text-based AI and cannot physically show you something. However, I can provide information, answer questions, or engage in a conversation on a wide range of topics. Let me know how I can assist you today!', '2025-10-13 14:16:58'),
(9, 'give me code', NULL, '2025-10-13 14:17:07'),
(10, '', 'Sure, here is an example of a simple code snippet in Python that prints \"Hello, World!\":\n\n```python\nprint(\"Hello, World!\")\n```\n\nLet me know if you need help with anything else!', '2025-10-13 14:17:09'),
(11, 'okay bye', NULL, '2025-10-13 14:17:21'),
(12, '', 'Goodbye! Have a great day!', '2025-10-13 14:17:23'),
(13, 'hey', NULL, '2025-10-13 15:32:50'),
(14, '', 'Hello! How can I assist you today?', '2025-10-13 15:32:55'),
(15, 'hey', NULL, '2025-10-13 19:51:07'),
(16, '', 'Hello! How can I help you today?', '2025-10-13 19:51:11'),
(17, 'hi', NULL, '2026-03-16 17:14:16'),
(18, '', 'Hello! How can I help you today?', '2026-03-16 17:14:20');
